from langchain_core.documents import Document

def rrf_merge(
    ranked_lists: list[list[Document]],
    k: int = 60,
    top_n: int = 6,
) -> list[Document]:
    """Merge N ranked lists with Reciprocal Rank Fusion."""
    scores: dict[str, float] = {}
    doc_map: dict[str, Document] = {}

    for ranked in ranked_lists:
        for rank, doc in enumerate(ranked):
            key = doc.page_content
            scores[key] = scores.get(key, 0.0) + 1.0 / (k + rank + 1)
            doc_map[key] = doc

    ordered = sorted(scores, key=scores.__getitem__, reverse=True)
    return [doc_map[key] for key in ordered[:top_n]]

# Compare: first-seen dedup vs RRF
async def multi_query_rrf(question, retriever, queries, top_n=6):
    all_results = await asyncio.gather(*[retriever.ainvoke(q) for q in queries])
    return rrf_merge(list(all_results), top_n=top_n)

# First-seen order often puts the original query's docs first regardless of
# how well they rank across all sub-queries. RRF rewards consensus.
docs_rrf = asyncio.run(multi_query_rrf(
    question, retriever, sub_queries, top_n=6
